Write-Host "Diagnóstico do App Instalado" -ForegroundColor Cyan&#10;&#10;# Verificar caminhos&#10;$appPaths = @(&#10;    "C:\Program Files\Universe da Empada",&#10;    "$env:LOCALAPPDATA\Programs\universe-empada-desktop"&#10;)&#10;&#10;foreach ($appPath in $appPaths) {&#10;    if (Test-Path $appPath) {&#10;        Write-Host "\n📁 App encontrado em: $appPath" -ForegroundColor Green&#10;        &#10;        # Procurar backend&#10;        $backendFiles = Get-ChildItem $appPath -Recurse -Filter "server.js" -ErrorAction SilentlyContinue&#10;        if ($backendFiles) {&#10;            Write-Host "✅ Backend encontrado:" -ForegroundColor Green&#10;            foreach ($file in $backendFiles) {&#10;                Write-Host "   - $($file.FullName)" -ForegroundColor Gray&#10;            }&#10;        } else {&#10;            Write-Host "❌ Backend NÃO encontrado!" -ForegroundColor Red&#10;        }&#10;    }&#10;}&#10;&#10;# Verificar logs&#10;$logPath = "$env:APPDATA\universe-empada-desktop\logs\app.log"&#10;if (Test-Path $logPath) {&#10;    Write-Host "\n📋 Últimos logs:" -ForegroundColor Yellow&#10;    Get-Content $logPath -Tail 20&#10;}
